import com.example.grundfos_summer_app.ui.viewmodel.MainViewModel
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

private val GrundfosRed = Color(0xFFE4002B)
private val GrundfosDarkGrey = Color(0xFF455A64)

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun ErrorScreen(
    onBack: () -> Unit,
    viewModel: MainViewModel = viewModel()
) {
    val uiState by viewModel.uiState.collectAsStateWithLifecycle()
    val dateFormat = SimpleDateFormat("HH:mm:ss", Locale.getDefault())

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("Logy a události") },
                navigationIcon = {
                    IconButton(onClick = onBack) {
                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Zpět")
                    }
                }
            )
        }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(16.dp)
        ) {
            Text(
                text = "Posledních 10 událostí",
                style = MaterialTheme.typography.titleMedium,
                modifier = Modifier.padding(bottom = 8.dp)
            )

            LazyColumn(
                modifier = Modifier
                    .weight(1f)
                    .fillMaxWidth()
                    .border(1.dp, Color.LightGray, RoundedCornerShape(8.dp))
                    .clip(RoundedCornerShape(8.dp)),
                contentPadding = PaddingValues(8.dp),
                verticalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                if (uiState.logs.isEmpty()) {
                    item {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(32.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            Text("Žádné záznamy", color = Color.Gray)
                        }
                    }
                } else {
                    items(uiState.logs, key = { it.id }) { log ->
                        LogItem(
                            log = log,
                            isSelected = uiState.selectedLog?.id == log.id,
                            onTap = { viewModel.selectLog(log) },
                            timeStr = dateFormat.format(Date(log.timestamp))
                        )
                    }
                }
            }

            Spacer(modifier = Modifier.height(16.dp))

            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                val isResetEnabled = uiState.selectedLog?.isError == true

                Button(
                    onClick = { viewModel.resetErrors() },
                    modifier = Modifier.weight(1f),
                    enabled = isResetEnabled,
                    colors = ButtonDefaults.buttonColors(
                        containerColor = GrundfosRed,
                        disabledContainerColor = Color.LightGray
                    ),
                    shape = RoundedCornerShape(8.dp)
                ) {
                    Icon(Icons.Default.Refresh, contentDescription = null, modifier = Modifier.size(18.dp))
                    Spacer(Modifier.padding(horizontal = 4.dp))
                    Text("RESET CHYBY", fontWeight = FontWeight.Bold)
                }

                OutlinedButton(
                    onClick = { viewModel.clearLogs() },
                    modifier = Modifier.weight(1f),
                    colors = ButtonDefaults.outlinedButtonColors(
                        contentColor = GrundfosDarkGrey
                    ),
                    shape = RoundedCornerShape(8.dp)
                ) {
                    Icon(Icons.Default.Delete, contentDescription = null, modifier = Modifier.size(18.dp))
                    Spacer(Modifier.padding(horizontal = 4.dp))
                    Text("SMAZAT VŠE")
                }
            }
        }
    }
}

@Composable
private fun LogItem(
    log: LogEntry,
    isSelected: Boolean,
    onTap: () -> Unit,
    timeStr: String
) {
    val backgroundColor = if (log.isError) {
        if (isSelected) GrundfosRed.copy(alpha = 0.9f) else GrundfosRed.copy(alpha = 0.1f)
    } else {
        if (isSelected) Color.LightGray else Color.Transparent
    }

    val contentColor = if (log.isError && isSelected) {
        Color.White
    } else if (log.isError) {
        GrundfosRed
    } else {
        Color.Black
    }

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .clickable { onTap() }
            .border(
                width = if (isSelected) 2.dp else 0.dp,
                color = if (isSelected) GrundfosDarkGrey else Color.Transparent,
                shape = RoundedCornerShape(8.dp)
            ),
        colors = CardDefaults.cardColors(
            containerColor = backgroundColor
        ),
        shape = RoundedCornerShape(8.dp)
    ) {
        Row(
            modifier = Modifier.padding(12.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            Icon(
                imageVector = if (log.isError) Icons.Default.Warning else Icons.Default.Info,
                contentDescription = null,
                tint = contentColor,
                modifier = Modifier.size(24.dp)
            )

            Column(modifier = Modifier.padding(start = 12.dp)) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween
                ) {
                    Text(
                        text = if (log.isError) "CHYBA" else "INFO",
                        style = MaterialTheme.typography.labelSmall,
                        fontWeight = FontWeight.Black,
                        color = contentColor
                    )
                    Text(
                        text = timeStr,
                        style = MaterialTheme.typography.labelSmall,
                        color = contentColor.copy(alpha = 0.7f)
                    )
                }
                Text(
                    text = log.message,
                    style = MaterialTheme.typography.bodyMedium,
                    fontWeight = if (log.isError) FontWeight.Bold else FontWeight.Normal,
                    color = contentColor
                )
            }
        }
    }
}

